import json
from datetime import datetime

# Load opportunities data from var_functions.query_db:28
result1 = [
    {"Id": "#006Wt000007B5jWIAS", "OwnerId": "005Wt000003NFB8IAO", "OppCreated": "2022-11-01T10:45:36.000+0000", "CloseDate": "2023-04-28", "ContractId": "800Wt00000DE97BIAT", "ContractSigned": "2023-05-16"},
    {"Id": "006Wt000007B8RLIA0", "OwnerId": "005Wt000003NJgAIAW", "OppCreated": "2022-11-15T10:32:45.000+0000", "CloseDate": "2023-04-10", "ContractId": "800Wt00000DE9aDIAT", "ContractSigned": "2023-02-28"}
]

# Load contracts signed in April from var_functions.query_db:30
result2 = [
    {"OwnerId": "005Wt000003NDEBIA4", "CreatedDate": "2022-06-15T10:20:30.000+0000", "CompanySignedDate": "2023-04-15"}
]

# Combine all data
all_data = []

# Process opportunities with contracts (result1)
for row in result1:
    created_date = datetime.fromisoformat(row['OppCreated'].replace('Z', '+00:00'))
    contract_date = datetime.fromisoformat(row['ContractSigned'] + 'T00:00:00+00:00')
    sales_cycle_days = (contract_date - created_date).days
    all_data.append({
        'OwnerId': row['OwnerId'],
        'sales_cycle_days': sales_cycle_days
    })

# Process contracts signed in April (result2) 
for row in result2:
    created_date = datetime.fromisoformat(row['CreatedDate'].replace('Z', '+00:00'))
    contract_date = datetime.fromisoformat(row['CompanySignedDate'] + 'T00:00:00+00:00')
    sales_cycle_days = (contract_date - created_date).days
    all_data.append({
        'OwnerId': row['OwnerId'],
        'sales_cycle_days': sales_cycle_days
    })

# Group by OwnerId and calculate average sales cycle
from collections import defaultdict

agent_cycles = defaultdict(list)
for row in all_data:
    agent_cycles[row['OwnerId']].append(row['sales_cycle_days'])

agent_avg = {}
for owner_id, cycles in agent_cycles.items():
    avg_cycle = sum(cycles) / len(cycles)
    agent_avg[owner_id] = avg_cycle

# Find agent with minimum average
if agent_avg:
    quickest_agent = min(agent_avg, key=agent_avg.get)
    result = {"agent_id": quickest_agent, "avg_cycle": agent_avg[quickest_agent]}
else:
    result = None

print('__RESULT__:')
print(json.dumps(result))

